request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?rollUpElem ?rollUpName ?sub ?subName ?calcProp ?calcName
WHERE {
  ?rollUpElem rdf:type vocab:block .
  ?rollUpElem vocab:NamedElement_name ?rollUpName .
  FILTER(CONTAINS(LCASE(STR(?rollUpName)), LCASE("ErrorRollUpPatternElement")))

  OPTIONAL {
    ?rollUpElem vocab:Element_ownedElement+ ?sub .
    OPTIONAL { ?sub vocab:NamedElement_name ?subName . }
  }

  OPTIONAL {
    ?rollUpElem vocab:Element_ownedElement+ ?calcProp .
    ?calcProp rdf:type ?calcType .
    OPTIONAL { ?calcProp vocab:NamedElement_name ?calcName . }
    FILTER(
      CONTAINS(LCASE(STR(?calcName)), LCASE("errorReq"))
      || CONTAINS(LCASE(STR(?calcName)), LCASE("errorCBECalc"))
      || CONTAINS(LCASE(STR(?calcName)), LCASE("errorReqCalc"))
      || CONTAINS(LCASE(STR(?calcName)), LCASE("RootSumSquared"))
    )
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?budgetView ?budgetName ?rollupElem ?rollupName ?errorReq ?errorReqName ?marginCalc ?marginCalcName
WHERE {
  ?budgetView rdf:type vocab:view ;
              vocab:NamedElement_name ?budgetName .
  FILTER(CONTAINS(LCASE(STR(?budgetName)), LCASE("Error%20Budget")))

  OPTIONAL {
    ?budgetView vocab:Element_ownedElement+ ?rollupElem .
  }

  ?rollupElem rdf:type vocab:value%20property .
  ?rollupElem vocab:NamedElement_name ?errorReqName .
  FILTER(CONTAINS(LCASE(STR(?errorReqName)), LCASE("errorReq")))

  OPTIONAL {
    ?rollupElem vocab:Element_owner^ ?marginCalc .
    ?marginCalc vocab:NamedElement_name ?marginCalcName .
    FILTER(
      CONTAINS(LCASE(STR(?marginCalcName)), LCASE("RootSumSquared"))
      || CONTAINS(LCASE(STR(?marginCalcName)), LCASE("errorReqCalc"))
      || CONTAINS(LCASE(STR(?marginCalcName)), LCASE("errorCBECalc"))
    )
  }

  OPTIONAL { ?rollupElem vocab:NamedElement_name ?errorReq . }
  OPTIONAL { ?rollupElem rdf:type ?rollupType . BIND(STR(?rollupType) AS ?rollupName) }
}
LIMIT 25
